float.expression:
if(childIsCommonChild,
				1,
				if(childHasReceivedAlimony & ((childHasPaidAlimony != true) | (childAlimonyTotalAmountReceived > childAlimonyTotalAmountPaid)),
					childIs18DeductionInternalCoefficient,
					if(childHasPaidAlimony,
						1 - childIs18DeductionInternalCoefficient,
						1)))

if(childIsCommonChild,
				1,
				if(childHasReceivedAlimony & ((childHasPaidAlimony != true) | (childAlimonyTotalAmountReceived > childAlimonyTotalAmountPaid)),
					childIs18DeductionInternalCoefficient,
					if(childHasPaidAlimony,
						1 - childIs18DeductionInternalCoefficient,
						1)))

integer.expression:
