string.expression:
if(notifySearchResult != true,
							if(securityList_TaxValueBaseType == 'chf', 'count',
							if(securityList_TaxValueBaseType == 'percent', 'nominal',
							'saldo')),
						if(securityList_KindGroupFromDB_Internal == 'BOND' | (securityList_KindGroupFromDB_Internal == 'DEVT' & securityList_QuotationTypeFromDB_Internal == 'PERCENT'), 'nominal', 'count')
						)

if(in(securityList_Kind, 'stocks', 'options', 'participation', 'shares', 'sharesWithTaxation', 'sharesWithoutTaxation', 'bonds', 'fixDeposit', 'mediumTermNotes', 'derivatives'),
				'kindDebtorBank',
				if(in(securityList_Kind, 'otherCredits', 'condominiums', 'coOwnerShip', 'variousAccounts', 'bankAccount'),
					'full',
					if(in(securityList_Kind, 'winnings'),
						'description',
						if(in(securityList_Kind, 'depot'),
							'accountNr',
							if(in(securityList_Kind, 'collectiveInvestments'),
								'debtor',
								if(in(securityList_Kind, 'loan'),
									'debtorName',
									if(in(securityList_Kind, 'cryptocurrencies'),
