										null)))))))

float.expression:
if(securityList_FaceValueQuantityType == 'saldo',
	securityDetail_NominalValue_CHF_YearEnd_Internal,
	if(securityList_TaxValueBaseType == 'percent',
		securityDetail_NominalValue_CHF_YearEnd_Internal * securityList_TaxValueBase div 100,
		if(securityList_TaxValueBaseType == 'chf',
			if(securityList_FaceValueQuantityType == 'count',
				securityDetail_FaceValueQuantity_EndYear_Or_Default_Internal * securityDetail_TaxValueBase_Calculated,
				if(securityList_NominalAmount != null & securityList_NominalAmount != 0,
					securityDetail_FaceValueQuantity_EndYear_Or_Default_Internal div securityList_NominalAmount, null) * securityDetail_TaxValueBase_Calculated),
					null)))

if(securityList_FaceValueQuantityType != 'count', securityDetail_FaceValueQuantity_EndYear_Or_Default_Internal,
						if(securityList_NominalAmount != null & securityList_NominalAmount != 0, securityDetail_FaceValueQuantity_EndYear_Internal * securityList_NominalAmount,
						null))

if(securityList_FaceValueQuantityType == 'count', securityDetail_FaceValueQuantity_EndYear_Or_Default_Internal,
						if(securityDetail_TaxValueBase_Calculated != null & securityDetail_TaxValueBase_Calculated != 0, securityDetail_FaceValueQuantity_EndYear_Or_Default_Internal div securityDetail_TaxValueBase_Calculated,
						null))

string.expression:
if(securityList_Rubric != 'all', enum('secRubric', securityList_Rubric, true), 
						smartConcat(if(securityList_HasRubricA, enum('secRubric', 'withHoldingTax', true), null), ', ',
							if(securityList_HasRubricB, enum('secRubric', 'withoutHoldingTax', true), null), ', ',
							if(securityList_HasRubricC, enum('secRubric', 'typeDAUS', true), null), ', ')
						)

integer.expression:
if(AB_RowType == 'security', if(AB_Rubric == 'withHoldingTax', AB_GrossRevenue,
